class CountIntervals {
    private TreeSet<int[]> intervals;
    private int count;

    public CountIntervals() {
        intervals = new TreeSet<>((a, b) -> a[0] - b[0]);
        count = 0;
    }

    public void add(int left, int right) {
        int[] interval = new int[] {left, right};
        int covered = 0;
        while (!intervals.isEmpty() && intervals.last()[1] >= left) {
            int[] last = intervals.pollLast();
            if (last[1] >= left) {
                left = Math.min(last[0], left);
                right = Math.max(last[1], right);
                covered += last[1] - last[0] + 1;
            } else {
                intervals.add(last);
                break;
            }
        }
        count += right - left + 1 - covered;
        intervals.add(new int[] {left, right});
    }

    public int count() {
        return count;
    }
}
